import{_ as t,c as a,o,aj as r}from"./chunks/framework.guNMSiFm.js";const m=JSON.parse('{"title":"Sample Apps","description":"","frontmatter":{},"headers":[],"relativePath":"guide/tutorials/sample-apps.md","filePath":"guide/tutorials/sample-apps.md","lastUpdated":1777621302000}'),i={name:"guide/tutorials/sample-apps.md"};function s(d,e,n,l,p,c){return o(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="sample-apps" tabindex="-1">Sample Apps <a class="header-anchor" href="#sample-apps" aria-label="Permalink to &quot;Sample Apps&quot;">​</a></h1><p>These repositories show complete client applications built around Iroha. Use them when you want to see SDK setup, account flows, signing, Torii calls, and UI integration in a larger codebase than the minimal tutorials.</p><p>The sample apps are examples, not production wallet templates. Review their dependency versions, network assumptions, and key-storage choices before copying code into a real product.</p><h2 id="available-apps" tabindex="-1">Available Apps <a class="header-anchor" href="#available-apps" aria-label="Permalink to &quot;Available Apps&quot;">​</a></h2><table tabindex="0"><thead><tr><th>App</th><th>Platform</th><th>What it demonstrates</th><th>Status</th></tr></thead><tbody><tr><td><a href="https://github.com/soramitsu/iroha-demo-javascript" target="_blank" rel="noreferrer">Iroha Demo JavaScript</a></td><td>Desktop app with Electron, Vue 3, Pinia, and Vite</td><td>Direct Torii connectivity through <code>@iroha/iroha-js</code>, local transaction signing, wallet balances and history, send/receive QR flows, staking, governance, explorer, and live E2E checks</td><td>Most complete current sample</td></tr><tr><td><a href="https://github.com/soramitsu/iroha-demo-android" target="_blank" rel="noreferrer">Iroha Demo Android</a></td><td>Android point app</td><td>Native Android project structure for a point-transfer style mobile application</td><td>Older mobile demo; use the <a href="/iroha-2-docs/guide/tutorials/kotlin-java.html">Android, Kotlin, and Java SDK page</a> for current SDK setup</td></tr><tr><td><a href="https://github.com/hyperledger-iroha/iroha/tree/i23-features/examples/ios/ConnectMinimalApp" target="_blank" rel="noreferrer"><code>examples/ios/ConnectMinimalApp</code></a></td><td>SwiftPM executable</td><td><code>NoritoNativeBridge</code> availability check, <code>ConnectSession</code> event stream intent, and diagnostics export intent</td><td>Iroha repository harness, but currently out of sync: the package path resolves to <code>examples/IrohaSwift</code>, and source references Connect helpers absent from <code>IrohaSwift/Sources</code></td></tr><tr><td><a href="https://github.com/hyperledger-iroha/iroha/tree/i23-features/examples/ios/NoritoDemo" target="_blank" rel="noreferrer"><code>examples/ios/NoritoDemo</code></a></td><td>SwiftUI iOS template</td><td>XcodeGen template with conditional <code>NoritoBridge</code> linkage and Iroha Connect UI code</td><td>Iroha repository template, but the project manifest does not declare the <code>IrohaSwift</code> package dependency imported by the sources</td></tr><tr><td><a href="https://github.com/hyperledger-iroha/iroha/tree/i23-features/examples/ios/NoritoDemoXcode" target="_blank" rel="noreferrer"><code>examples/ios/NoritoDemoXcode</code></a></td><td>SwiftUI Xcode project</td><td>Generated Xcode project with Swift sources importing <code>IrohaSwift</code> and conditionally using <code>NoritoBridgeKit</code></td><td>Iroha repository demo, but the checked-in Xcode project does not declare the <code>IrohaSwift</code> package dependency imported by the sources</td></tr><tr><td><a href="https://github.com/soramitsu/iroha-demo-ios" target="_blank" rel="noreferrer">Iroha Demo iOS</a></td><td>iOS point app</td><td>Xcode/CocoaPods project structure for a point-transfer style mobile application</td><td>Historical external demo; use the in-tree Swift examples and <a href="/iroha-2-docs/guide/tutorials/swift.html">Swift and iOS SDK page</a> for current setup</td></tr></tbody></table><h2 id="javascript-desktop-demo" tabindex="-1">JavaScript Desktop Demo <a class="header-anchor" href="#javascript-desktop-demo" aria-label="Permalink to &quot;JavaScript Desktop Demo&quot;">​</a></h2><p>Start with the JavaScript demo if you want a working reference for current application flows. It is a desktop client that talks directly to Torii through the in-repo JavaScript SDK, without a separate backend. The app includes:</p><ul><li>first-run account setup and key import or generation</li><li>endpoint settings for SORA Nexus networks</li><li>locally signed transfers submitted to Torii</li><li>wallet balances, transaction history, and explorer views</li><li>QR-based receive and send flows</li><li>staking and governance screens</li><li>live Electron E2E checks against configured Torii endpoints</li></ul><p>The JavaScript demo requires Node.js 20+ and a Rust toolchain for the native <code>iroha_js_host</code> module. Its README contains the current install, build, test, and live E2E commands.</p><h2 id="mobile-samples" tabindex="-1">Mobile Samples <a class="header-anchor" href="#mobile-samples" aria-label="Permalink to &quot;Mobile Samples&quot;">​</a></h2><p>The external Android and iOS point-app repositories are historical examples of the original point-app concept and mobile project layout. Swift/iOS sample code also exists in the <a href="https://github.com/hyperledger-iroha/iroha/tree/i23-features/examples/ios" target="_blank" rel="noreferrer">Iroha repository&#39;s <code>examples/ios/</code> directory</a>, but its checked-in project manifests are currently out of sync with the package API and dependency layout. The current Android SDK lives under <code>java/iroha_android/</code>.</p><p>Use the SDK pages for new application setup:</p><ul><li><a href="/iroha-2-docs/guide/tutorials/kotlin-java.html">Android, Kotlin, and Java</a></li><li><a href="/iroha-2-docs/guide/tutorials/swift.html">Swift and iOS</a></li></ul><p>For new mobile work, confirm the SDK version, Torii endpoint shape, account format, and transaction format against the current <a href="https://github.com/hyperledger-iroha/iroha/tree/i23-features" target="_blank" rel="noreferrer">Iroha <code>i23-features</code> branch</a> before porting code from either external mobile demo.</p>',14)])])}const u=t(i,[["render",s]]);export{m as __pageData,u as default};
